import Link from 'next/link'
import styles from './page.module.css'
import { fetchApi, type Quest, type NewsItem, type ReviewItem, type PageBlock } from '@/lib/api'

/* ==================== API FETCHERS ==================== */

async function getQuests() {
  try {
    return await fetchApi('/quests') as Quest[]
  } catch {
    return []
  }
}

async function getNews() {
  try {
    return await fetchApi('/news') as NewsItem[]
  } catch {
    return []
  }
}

async function getReviews() {
  try {
    return await fetchApi('/reviews') as ReviewItem[]
  } catch {
    return []
  }
}

async function getHomeBlocks() {
  try {
    return await fetchApi('/content?pageKey=HOME') as PageBlock[]
  } catch {
    return []
  }
}

/* ==================== MAPPING HELPERS ==================== */

function difficultyToLevel(d: string): number {
  return d === 'easy' ? 1 : d === 'medium' ? 3 : 5
}

function formatDuration(mins: number): string {
  return `${mins} минут`
}

function formatPlayers(min: number, max: number): string {
  return `${min}-${max} игроков`
}

function getTagVariant(genre: string): 'horror' | 'detective' | 'kids' | undefined {
  if (genre === 'хоррор') return 'horror'
  if (genre === 'детектив') return 'detective'
  if (genre === 'детский') return 'kids'
  return undefined
}

type QuestCard = {
  id: string
  title: string
  subtitle?: string
  tag: string
  tagVariant?: 'horror' | 'detective' | 'kids'
  difficulty: number
  duration: string
  players: string
  age: string
  poster: string
}

function mapQuest(q: Quest): QuestCard {
  return {
    id: q.id,
    title: q.name,
    subtitle: q.subtitle || undefined,
    tag: q.genre,
    tagVariant: getTagVariant(q.genre),
    difficulty: difficultyToLevel(q.difficulty),
    duration: formatDuration(q.durationMinutes),
    players: formatPlayers(q.minPlayers, q.maxPlayers),
    age: q.ageRestriction || '12+',
    poster: q.previewImage?.url || '',
  }
}

/* ==================== HELPERS ==================== */

function tagClass(variant?: string): string {
  if (variant === 'horror') return `${styles.questCardTag} ${styles.questCardTagHorror}`
  if (variant === 'detective') return `${styles.questCardTag} ${styles.questCardTagDetective}`
  if (variant === 'kids') return `${styles.questCardTag} ${styles.questCardTagKids}`
  return styles.questCardTag
}

function DifficultyDots({ level }: { level: number }) {
  return (
    <span className={styles.questCardDifficulty} aria-label={`Сложность ${level} из 5`}>
      {[1, 2, 3, 4, 5].map((i) => (
        <i
          key={i}
          className={
            i <= level
              ? styles.questCardDot
              : `${styles.questCardDot} ${styles.questCardDotOff}`
          }
        />
      ))}
    </span>
  )
}

