const serviceNames = ['Lounge', 'Игровая', 'Кафе', 'Шоу-программа', 'Квесты', 'Торт', 'Пиньята']

/* ==================== QUEST SLIDER COMPONENT ==================== */

function QuestSlider({ title, quests }: { title: string; quests: QuestCard[] }) {
  return (
    <section className={styles.section}>
      <div className="container">
        <h2 className={`${styles.sectionTitle} title-effect`}>{title}</h2>
      </div>
      <div className={styles.questsSlider}>
        <button className={`${styles.sliderArrow} ${styles.sliderArrowPrev}`} aria-label="Назад">
          {ArrowPrevSvg}
        </button>
        <div className={styles.questsSliderTrack}>
          {quests.map((quest) => (
            <article
              key={quest.id}
              className={styles.questCard}
              style={{ '--poster': `url('${quest.poster}')` } as React.CSSProperties}
            >
              <div
                className={styles.questCardPoster}
                style={{ backgroundImage: `url('${quest.poster}')` }}
              />
              <span className={tagClass(quest.tagVariant)}>{quest.tag}</span>
              <div className={styles.questCardBody}>
                <h3 className={styles.questCardTitle}>
                  {quest.title}
                  {quest.subtitle && (
                    <span className={styles.questCardSub}>{quest.subtitle}</span>
                  )}
                </h3>
                <div className={styles.questCardMeta}>
                  <DifficultyDots level={quest.difficulty} />
                  <span className={styles.questCardInfo}>{quest.duration}</span>
                  <span className={styles.questCardInfo}>{quest.players}</span>
                  <span className={styles.questCardInfo}>{quest.age}</span>
                </div>
              </div>
              {/* Hover overlay */}
              <div className={styles.questCardHover}>
                <span className={styles.questCardHoverIcon}>{HoverIconSvg}</span>
                <h3 className={styles.questCardHoverTitle}>
                  Игровая и кафе<br />для вашего ребенка
                </h3>
                <p className={styles.questCardHoverText}>
                  Проведите этот день максимально весело. Отдохните после квеста в наших кафе и игровой
                </p>
                <div className={styles.questCardHoverActions}>
                  <Link href="/quests" className={`${styles.btn} ${styles.btnPink} ${styles.btnFull}`}>
                    Перейти в квест
                  </Link>
                  <Link href="/holidays" className={`${styles.btn} ${styles.btnGreen} ${styles.btnFull}`}>
                    Забронировать столик
                  </Link>
                </div>
              </div>
              <Link href={`/quests/${quest.id}`} className={styles.questCardLink} aria-label="Подробнее" />
            </article>
          ))}
        </div>
        <button className={`${styles.sliderArrow} ${styles.sliderArrowNext}`} aria-label="Вперед">
          {ArrowNextSvg}
        </button>
      </div>
    </section>
  )
}

/* ==================== PAGE ==================== */

export default async function Home() {
  const [allQuests, newsData, reviewsData, homeBlocks] = await Promise.all([
    getQuests(),
    getNews(),
    getReviews(),
    getHomeBlocks(),
  ])

  const questsWithActors = allQuests
    .filter(q => q.hasActors && q.ageRestriction !== '0+')
    .map(mapQuest)

  const questsWithoutActors = allQuests
    .filter(q => !q.hasActors && q.ageRestriction !== '0+')
    .map(mapQuest)

  const kidsQuests = allQuests
    .filter(q => q.ageRestriction === '0+')
    .map(mapQuest)

  const newsItems = newsData.map(n => ({
    id: n.id,
    cardBg: n.cardBg || 'linear-gradient(180deg, #1a2010 0%, #07080a 100%)',
    coverTitle: n.coverTitle || n.title,
    coverSub: n.coverSub || undefined,
    coverVariant: n.coverVariant || undefined,
    date: new Date(n.date).toLocaleDateString('ru-RU', { day: 'numeric', month: 'long', year: 'numeric' }),
    title: n.title,
    text: n.content.substring(0, 100) + '...',
  }))

  const reviewItems = reviewsData.map(r => ({
    id: r.id,
    name: r.name,
    date: new Date(r.createdAt).toLocaleDateString('ru-RU', { day: 'numeric', month: 'long', year: 'numeric' }),
    text: r.text,
    source: r.source?.name || '',
  }))

  const heroTitle = homeBlocks.find(b => b.blockKey === 'hero_title')?.title || 'Самый большой квеструм и площадки для праздников во Владивостоке'
  const heroFeatures = (() => { try { return JSON.parse(homeBlocks.find(b => b.blockKey === 'hero_features')?.extraJson || '[]') as string[] } catch { return [] } })()
  const heroCtaText = homeBlocks.find(b => b.blockKey === 'hero_cta_text')?.title || 'Забронируйте праздник прямо сейчас'
  const holidayCardsData = (() => { try { return JSON.parse(homeBlocks.find(b => b.blockKey === 'holiday_cards')?.extraJson || '[]') as Array<{ kicker: string; title: string; poster: string }> } catch { return [] } })()

  return (
    <main>
      {/* ==================== HERO ==================== */}
      <section className={styles.hero}>
        <div className={`container ${styles.heroInner}`}>
          <div className={styles.heroContent}>
            <h1 className={styles.heroTitle}>
              <span className={`${styles.heroTitleLine} title-effect`}>
                Самый большой квеструм
              </span>
              <span className={styles.heroTitleLine}>
                и площадки для{' '}
                <Link href="/holidays" className={styles.heroTitleLink}>
                  праздников
                </Link>
              </span>
              <span className={styles.heroTitleLine}>во Владивостоке</span>
            </h1>

            <div className={styles.heroButtons}>
              <Link href="/quests" className={`${styles.btn} ${styles.btnPink}`}>
                Забронировать квест
              </Link>
              <Link href="/holidays" className={`${styles.btn} ${styles.btnGreen}`}>
                Отметить праздник
              </Link>
            </div>

            <ul className={styles.heroFeatures}>
              {(heroFeatures.length > 0 ? heroFeatures : [
                '16 разнообразных квестов для любой компании',
                'три зала кафе, площадью более 350 м²',
                'ваш праздник «под ключ»',
                'работаем с 2015 года',
              ]).map((feature, idx) => (
                <li key={idx} className={styles.heroFeature}>
                  <span className={styles.heroCheck}>{CheckSvg}</span>
                  <span>{feature}</span>
                </li>
              ))}
            </ul>
          </div>
        </div>

        {/* Photo collage — desktop only */}
        <div className={styles.heroMedia} aria-hidden="true">
          <div className={`${styles.heroPhoto} ${styles.heroPhoto1}`} />
          <div className={`${styles.heroPhoto} ${styles.heroPhoto2}`} />
          <div className={`${styles.heroPhoto} ${styles.heroPhoto3}`} />

          <Link href="/holidays" className={styles.heroCta}>
            <span className={styles.heroCtaText}>
              {heroCtaText.split('\n').map((line, i, arr) => (
                <span key={i}>{line}{i < arr.length - 1 && <br />}</span>
              ))}
            </span>
            <span className={styles.heroCtaArrow}>{ArrowRightSvg}</span>
          </Link>
        </div>
      </section>

      {/* ==================== QUESTS WITH ACTORS ==================== */}
      <QuestSlider title="Квесты с актерами во Владивостоке" quests={questsWithActors} />

      {/* ==================== QUESTS WITHOUT ACTORS ==================== */}
      <QuestSlider title="Квесты без актеров во Владивостоке" quests={questsWithoutActors} />

      {/* ==================== KIDS QUESTS ==================== */}
      <QuestSlider title="Квесты для детей во Владивостоке" quests={kidsQuests} />

      {/* ==================== KIDS HOLIDAYS ==================== */}
      <section className={`${styles.section} ${styles.sectionHolidays}`}>
        <div className="container">
          <div className={styles.holidaysIntro}>
            <h2 className={styles.holidaysIntroTitle}>
              <span className={styles.holidaysIntroLine}>Устройте незабываемый</span>
              <span className={`${styles.holidaysIntroLine} title-effect`}>
                праздник для вашего ребенка
              </span>
              <span className={styles.holidaysIntroLine}>в семейном центре «Пандорум»</span>
            </h2>
          </div>

          <div className={styles.holidaysGrid}>
            {holidayCardsData.map((holiday, idx) => (
              <article
                key={idx}
                className={styles.holidayCard}
                style={{ '--poster': `url('${holiday.poster}')` } as React.CSSProperties}
              >
                <span className={styles.holidayCardKicker}>{holiday.kicker}</span>
                <h3 className={styles.holidayCardTitle}>
                  {holiday.title.split('\n').map((line, i) => (
                    <span key={i}>
                      {line}
                      {i < holiday.title.split('\n').length - 1 && <br />}
                    </span>
                  ))}
                </h3>
                <Link href="/holidays" className={styles.holidayCardBtn}>
                  подробнее
                </Link>
              </article>
            ))}
          </div>
        </div>
      </section>

      {/* ==================== SERVICES ICONS ==================== */}
      <section className={`${styles.section} ${styles.sectionServices}`}>
        <div className="container">
          <p className={styles.servicesHint}>для каждого праздника вы можете подобрать</p>
          <div className={styles.servicesRow}>
            {serviceNames.map((name, idx) => (
              <div key={idx} className={styles.serviceItem}>
                <div className={styles.serviceItemIcon}>{serviceIcons[idx]}</div>
                <span className={styles.serviceItemName}>{name}</span>
              </div>
            ))}
          </div>
        </div>
      </section>

      {/* ==================== BG PREFOOTER (NEWS + REVIEWS) ==================== */}
      <div
        className={styles.bgPrefooter}
        style={{ backgroundImage: `url('/images/main/after-footer-bg.jpg')` }}
      >
        {/* ==================== NEWS ==================== */}
        <section className={styles.section}>
          <div className="container">
            <h2 className={`${styles.sectionTitle} title-effect`}>Новости и акции</h2>
            <div className={styles.newsGrid}>
              {newsItems.map((item) => (
                <article
                  key={item.id}
                  className={styles.newsCard}
                  style={{ '--card-bg': item.cardBg } as React.CSSProperties}
                >
                  <div
                    className={`${styles.newsCardCover} ${
                      item.coverVariant === 'discount' ? styles.newsCardCoverDiscount : ''
                    }`}
                  >
                    <span className={styles.newsCardCoverTitle}>
                      {item.coverTitle.split('\n').map((line, i) => (
                        <span key={i}>
                          {line}
                          {i < item.coverTitle.split('\n').length - 1 && <br />}
                        </span>
                      ))}
                      {item.coverSub && (
                        <span className={styles.newsCardCoverSub}>{item.coverSub}</span>
                      )}
                    </span>
                  </div>
                  <div className={styles.newsCardContent}>
                    <span className={styles.newsCardDate}>{item.date}</span>
                    <h3 className={styles.newsCardTitle}>{item.title}</h3>
                    <p className={styles.newsCardText}>{item.text}</p>
                    <Link href="#" className={styles.newsCardLink}>
                      подробнее
                    </Link>
                  </div>
                </article>
              ))}
            </div>
          </div>
        </section>

        {/* ==================== REVIEWS ==================== */}
        <section className={styles.section}>
          <div className="container">
            <h2 className={`${styles.sectionTitle} title-effect`}>Отзывы гостей</h2>
            <div className={styles.reviewsSlider}>
              <button
                className={`${styles.sliderArrow} ${styles.sliderArrowPrev}`}
                aria-label="Назад"
              >
                <svg
                  width="20"
                  height="20"
                  viewBox="0 0 24 24"
                  fill="none"
                  stroke="currentColor"
                  strokeWidth="2.5"
                  strokeLinecap="round"
                  strokeLinejoin="round"
                >
                  <polyline points="15 18 9 12 15 6" />
                </svg>
              </button>
              <div className={styles.reviewsSliderTrack}>
                {reviewItems.map((review) => (
                  <article key={review.id} className={styles.reviewCard}>
                    <div className={styles.reviewCardHeader}>
                      <span className={styles.reviewCardName}>{review.name}</span>
                      <span className={styles.reviewCardDate}>{review.date}</span>
                    </div>
                    <div className={styles.reviewCardStars}>★★★★★</div>
                    <p className={styles.reviewCardText}>{review.text}</p>
                    <span className={styles.reviewCardSource}>{review.source}</span>
                  </article>
                ))}
              </div>
              <button
                className={`${styles.sliderArrow} ${styles.sliderArrowNext}`}
                aria-label="Вперед"
              >
                <svg
                  width="20"
                  height="20"
                  viewBox="0 0 24 24"
                  fill="none"
                  stroke="currentColor"
                  strokeWidth="2.5"
                  strokeLinecap="round"
                  strokeLinejoin="round"
                >
                  <polyline points="9 18 15 12 9 6" />
                </svg>
              </button>
            </div>
          </div>
        </section>
      </div>
      {/* /.bg-prefooter */}

      <div className={styles.prefooterDivider} />
    </main>
  )
}
